BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?c ?name ?spec WHERE {
  ?c rdf:type vocab:constraint .
  ?c vocab:NamedElement_name ?name .
  OPTIONAL { ?c vocab:Constraint_specification ?spec }
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS")) || CONTAINS(LCASE(STR(?name)), LCASE("phasing")) || CONTAINS(LCASE(STR(?name)), LCASE("alignment")))
}
LIMIT 50

